const Section2 = ({
  theme = 'light',
  games = gameCatalog,
  favoriteIds = [],
  authUser = null,
  onToggleFavorite = () => { },
  onAddGame = () => { },
}) => {
  const cardsPerBatch = 3
  const [search, setSearch] = useState('')
  const [genre, setGenre] = useState('All')
  const [franchise, setFranchise] = useState('All')
  const [platform, setPlatform] = useState('All')
  const [sortBy, setSortBy] = useState('popular')
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false)
  const [isLoading] = useState(false)
  const [visibleCount, setVisibleCount] = useState(cardsPerBatch)

  const franchiseOptions = useMemo(
    () => ['All', ...new Set(games.map((game) => getFranchise(game)))],
    [games]
  )

  const suggestions = useMemo(() => {
    const normalizedSearch = search.trim().toLowerCase()

    if (!normalizedSearch) return []

    return games
      .filter((game) =>
        game.title.toLowerCase().includes(normalizedSearch) ||
        game.studio.toLowerCase().includes(normalizedSearch)
      )
      .slice(0, 5)
  }, [games, search])

  const filteredGames = useMemo(() => {
    const normalizedSearch = search.trim().toLowerCase()

    return games
      .filter((game) => {
        const matchesSearch =
          !normalizedSearch ||
          game.title.toLowerCase().includes(normalizedSearch) ||
          game.studio.toLowerCase().includes(normalizedSearch)
        const matchesGenre = genre === 'All' || game.genre === genre
        const matchesFranchise =
          franchise === 'All' || getFranchise(game) === franchise
        const matchesPlatform = platform === 'All' || game.platform === platform
        const matchesFavorite = !showFavoritesOnly || favoriteIds.includes(game.id)

        return matchesSearch && matchesGenre && matchesFranchise && matchesPlatform && matchesFavorite
      })
      .sort((a, b) => {
        if (sortBy === 'latest') return b.releaseYear - a.releaseYear
        if (sortBy === 'rating') return b.rating - a.rating
        return b.popularity - a.popularity
      })
  }, [favoriteIds, franchise, games, genre, platform, search, showFavoritesOnly, sortBy])

  useEffect(() => {
    setVisibleCount(cardsPerBatch)
  }, [search, genre, franchise, platform, showFavoritesOnly, sortBy])

  const visibleGames = filteredGames.slice(0, visibleCount)
  const hasMoreGames = visibleCount < filteredGames.length

  return (
    <section id='section-2' className={`min-h-screen px-4 py-16 sm:px-6 lg:px-10 ${theme === 'dark' ? 'bg-[#111111] text-[#fff3e7]' : 'bg-[#fff7f1] text-[#4a1834]'}`}>
      <style>{`
        @keyframes section2-card-reveal {
          from {
            opacity: 0;
            transform: translateY(24px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>









      {/* framermotion  */}
      <motion.div
        className='mx-auto max-w-7xl'
        initial={{ opacity: 0, y: 26 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true, amount: 0.12 }}
        transition={{ duration: 0.55, ease: 'easeOut' }}
      >


 



        <div className='mb-10 flex flex-col gap-4 md:flex-row md:items-end md:justify-between'>
          <div className='max-w-3xl'>

            <h2 className='mt-3 text-3xl font-bold sm:text-4xl'>Games Library</h2>
          </div>

          <div className='flex flex-wrap gap-3'>
            <FavoriteButton
              active={showFavoritesOnly}
              onClick={() => setShowFavoritesOnly((current) => !current)}
              theme={theme}
              className={showFavoritesOnly ? 'ring-2 ring-[#f28c28]/40' : ''}
            />
            <Section2Button
              theme={theme}
              onClick={() => {
                setSearch('')
                setGenre('All')
                setFranchise('All')
                setPlatform('All')
                setSortBy('popular')
                setShowFavoritesOnly(false)
              }}
            >
              Reset Filters
            </Section2Button>
          </div>
        </div>

        <div className={`grid gap-4 rounded-[2rem] p-5 md:grid-cols-2 xl:grid-cols-5 ${theme === 'dark' ? 'border border-white/10 bg-[#1a1a1a] shadow-[0_18px_40px_rgba(0,0,0,0.35)]' : 'border border-[#e9cfc1] bg-white shadow-[0_18px_40px_rgba(93,30,65,0.08)]'}`}>
          <label className='relative flex flex-col gap-2'>
            <span className='text-xs uppercase tracking-[0.25em] text-[#9a5a33]'>Search</span>
            <input
              type='text'
              value={search}
              onChange={(event) => setSearch(event.target.value)}
              placeholder='Search by title or studio'
              className={`rounded-full px-4 py-3 text-sm outline-none transition ${theme === 'dark' ? 'border border-white/10 bg-[#111111] text-[#fff3e7] focus:border-[#f4a261]' : 'border border-[#ebd8cf] bg-[#fff7f1] text-[#4a1834] focus:border-[#d47b2f]'}`}
            />
            {search.trim() && suggestions.length > 0 ? (
              <div className={`absolute left-0 right-0 top-[calc(100%+0.5rem)] z-20 overflow-hidden rounded-[1.5rem] ${theme === 'dark' ? 'border border-white/10 bg-[#181818] shadow-[0_20px_40px_rgba(0,0,0,0.35)]' : 'border border-[#ebd8cf] bg-white shadow-[0_16px_35px_rgba(93,30,65,0.12)]'}`}>
                {suggestions.map((game) => (
                  <button
                    key={game.id}
                    type='button'
                    onMouseDown={() => setSearch(game.title)}
                    className={`flex w-full items-center justify-between px-4 py-3 text-left text-sm transition ${theme === 'dark' ? 'text-[#fff3e7] hover:bg-[#24111d]' : 'text-[#4a1834] hover:bg-[#fff1e6]'}`}
                  >
                    <span>{game.title}</span>
                    <span className={`text-xs uppercase tracking-[0.2em] ${theme === 'dark' ? 'text-[#f4a261]' : 'text-[#9a5a33]'}`}>{game.studio}</span>
                  </button>
                ))}
              </div>
            ) : null}
          </label>

          <FilterSelect label='Genre' value={genre} onChange={(event) => setGenre(event.target.value)} options={genres} theme={theme} />
          <FilterSelect label='Franchise' value={franchise} onChange={(event) => setFranchise(event.target.value)} options={franchiseOptions} theme={theme} />
          <FilterSelect label='Platform' value={platform} onChange={(event) => setPlatform(event.target.value)} options={platforms} theme={theme} />
          <FilterSelect label='Sort' value={sortBy} onChange={(event) => setSortBy(event.target.value)} options={['popular', 'latest', 'rating']} theme={theme} />
        </div>

        <div className={`mt-5 flex flex-wrap gap-3 text-sm ${theme === 'dark' ? 'text-[#c8b2bb]' : 'text-[#7b4861]'}`}>
          <span>{filteredGames.length} games found</span>
          <span>{genre === 'All' ? 'all genres' : genre}</span>
          <span>{franchise === 'All' ? 'all franchises' : franchise}</span>
          <span>{platform === 'All' ? 'all platforms' : platform}</span>
          <span>sorted by {sortBy}</span>
          <span>{showFavoritesOnly ? 'favorites only' : 'all library'}</span>
          <span>{favoriteIds.length} favorites saved</span>
          <span>{games.length - gameCatalog.length} admin-added games</span>
        </div>

        {isLoading ? (
          <div className='mt-8 rounded-[2rem] border border-dashed border-[#dfc6ba] bg-white p-10 text-center text-[#7b4861]'>
            {/* Loading games... //change */}
            <div className="animate-pulse grid gap-6 md:grid-cols-2 xl:grid-cols-3">
              {[...Array(6)].map((_, i) => (
                <div key={i} className="h-64 rounded-2xl bg-gray-300"></div>
              ))}
            </div>
          </div>
        ) : filteredGames.length === 0 ? (
          <div className='mt-8 rounded-[2rem] border border-dashed border-[#dfc6ba] bg-white p-10 text-center'>
            <h3 className='text-2xl font-bold'>No games found 😝</h3>
            {/* <p className='mt-2 text-[#7b4861]'>Search ya filters change karke dekho.</p> */}
          </div>
        ) : (
          <>
            {/* <div className='mt-8 grid gap-6 md:grid-cols-2 xl:grid-cols-3'> //change */}
            <motion.div layout className='mt-8 grid gap-6 md:grid-cols-2 xl:grid-cols-3'>
              {visibleGames.map((game, index) => {
                return (
                  <motion.article
                    layout //change
                    whileHover={{ y: -6 }} //change
                    key={game.id}
                    initial={{ opacity: 0, y: 28, scale: 0.98 }}
                    whileInView={{ opacity: 1, y: 0, scale: 1 }}
                    viewport={{ once: true, amount: 0.2 }}
                    transition={{ duration: 0.45, delay: Math.min(index * 0.08, 0.35), ease: 'easeOut' }}
                    className={`overflow-hidden rounded-[2rem] transition-all duration-300 hover:-translate-y-3 hover:ring-1 hover:ring-[#f4a261]/70 ${theme === 'dark' ? 'border border-white/10 bg-[#1a1a1a] shadow-[0_20px_35px_rgba(0,0,0,0.3)] hover:shadow-[0_28px_60px_rgba(242,140,40,0.15)]' : 'border border-[#ebd8cf] bg-white shadow-[0_20px_35px_rgba(93,30,65,0.08)] hover:shadow-[0_28px_60px_rgba(95,39,72,0.22)]'}`}
                  >
                    <GamePoster game={game} />

                    <div className='space-y-5 p-5'>
                      <p className={`text-sm leading-6 ${theme === 'dark' ? 'text-[#d6c1c9]' : 'text-[#6f3a56]'}`}>{game.description}</p>

                      <div className={`flex items-center justify-between rounded-full px-4 py-3 text-sm ${theme === 'dark' ? 'bg-[#111111]' : 'bg-[#fff3ea]'}`}>
                        <span className={theme === 'dark' ? 'text-[#f4a261]' : 'text-[#9a5a33]'}>Rating</span>
                        <span className={theme === 'dark' ? 'font-semibold text-[#fff3e7]' : 'font-semibold text-[#4a1834]'}>{game.rating}/10</span>
                      </div>

                      <div className='flex flex-wrap gap-3'>
                        <Section2Button theme={theme} as={Link} to={`/games/${game.id}`}>
                          Open Details
                        </Section2Button>
                        <FavoriteButton
                          active={favoriteIds.includes(game.id)}
                          onClick={() => onToggleFavorite(game.id)}
                          theme={theme}
                        />

                        <Section2Button theme={theme} as='a' href={game.trailer} target='_blank' rel='noreferrer'>
                          Watch Trailer
                        </Section2Button>

                        <Section2Button theme={theme} as='a' href={buildSteamSearch(game.title)} target='_blank' rel='noreferrer'>
                          Steam Link
                        </Section2Button>

                        <Section2Button theme={theme} as='a' href={buildSteamReviews(game.title)} target='_blank' rel='noreferrer'>
                          Steam Reviews
                        </Section2Button>
                      </div>
                    </div>
                  </motion.article>
                )
              })}
              {/* </div> //change */}
            </motion.div>
            {hasMoreGames ? (
              <div className='mt-8 flex justify-center'>
                <Section2Button theme={theme} onClick={() => setVisibleCount((current) => current + cardsPerBatch)}>
                  More
                </Section2Button>
              </div>
            ) : null}
          </>
        )}
      </motion.div>







    </section>
  )
}

export default Section2
